    , ITEM_CD     = #{ITEM_CD}
    , SUBJECT     = #{SUBJECT}
    , REQ_RMK     = #{REQ_RMK}
    , ATTACH_FILE_NO = #{ATTACH_FILE_NO}
    , MOD_DATE    = SYSDATE
    , MOD_USER_ID = #{ses.userId}
WHERE GATE_CD    = #{ses.gateCd}
  AND COMPANY_CD = #{COMPANY_CD}
  AND VC_NO      = #{VC_NO}

UPDATE STOCVOCM SET
